import json
import pandas as pd

# Load previous results
cases = locals()['var_function-call-10030256816200420512']
history_file = locals()['var_function-call-5672048893223626647']

with open(history_file, 'r') as f:
    history = json.load(f)

def clean_id(i):
    if i and isinstance(i, str):
        return i.lstrip('#')
    return i

start_date = pd.Timestamp('2023-05-02').tz_localize('UTC')
end_date = pd.Timestamp('2023-09-02').tz_localize('UTC')

valid_cases = []
for c in cases:
    c['id'] = clean_id(c['id'])
    c['ownerid'] = clean_id(c['ownerid'])
    closed_dt = pd.to_datetime(c['closeddate'])
    if start_date.date() <= closed_dt.date() <= end_date.date():
        c['closed_dt'] = closed_dt
        valid_cases.append(c)

print(f"Total Cases: {len(cases)}")
print(f"Valid Cases in Window: {len(valid_cases)}")

case_owners_map = {}
for h in history:
    cid = clean_id(h['caseid__c'])
    new_owner = clean_id(h['newvalue__c'])
    if cid not in case_owners_map:
        case_owners_map[cid] = []
    case_owners_map[cid].append(new_owner)

agent_stats = {}
debug_case_info = []

for c in valid_cases:
    cid = c['id']
    history_owners = case_owners_map.get(cid, [])

    if not history_owners:
        owners = [c['ownerid']]
        is_transferred = False
        owners_source = "Case.OwnerId"
    else:
        count_assignments = len(history_owners)
        owners = list(set(history_owners))
        if count_assignments > 1:
            is_transferred = True
        else:
            is_transferred = False
        owners_source = "History"

    debug_case_info.append({
        'id': cid,
        'owners': owners,
        'is_transferred': is_transferred,
        'owners_source': owners_source
    })

    for agent in owners:
        if agent not in agent_stats:
            agent_stats[agent] = {'processed_count': 0, 'handle_times': []}
        agent_stats[agent]['processed_count'] += 1
        # Calculate duration
        created_dt = pd.to_datetime(c['createddate'])
        duration = (c['closed_dt'] - created_dt).total_seconds()

        if not is_transferred:
             agent_stats[agent]['handle_times'].append(duration)

print("__RESULT__:")
print(json.dumps({
    'valid_cases_count': len(valid_cases),
    'agent_stats_keys': list(agent_stats.keys()),
    'sample_stats': list(agent_stats.values())[:3] if agent_stats else [],
    'debug_cases': debug_case_info[:5]
}, default=str))

